#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<long long>h(n);for(auto&x:h)scanf("%lld",&x);stack<int>st;long long best=0;for(int i=0;i<=n;i++){long long cur=(i==n)?-1:h[i];while(!st.empty()&&h[st.top()]>=cur){long long height=h[st.top()];st.pop();long long width=st.empty()?i:(i-st.top()-1);best=max(best,height*width);}st.push(i);}printf("%lld\n",best);}
